func newStandardDateCounter(reserveDays int64) *StandardDateCounter {
	now := time.Now()
	now = time.Date(now.Year(), now.Month(), now.Day(), 0, 0, 0, 0, now.Location())
	s := &StandardDateCounter{
		reserveDays:	reserveDays,
		counts:		make([]int64, reserveDays),
		lastUpdateDate:	now,
	}
	return s
}
